import java.util.Scanner;
import java.util.Arrays;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Validate input length to prevent buffer overflow
        if (name.length() > 10) {
            System.out.println("Input exceeds maximum length. Please enter a shorter name.");
            return;
        }

        // Sanitize input by trimming leading and trailing whitespace
        name = name.trim();

        // Copy input into a buffer of appropriate size
        byte[] buffer = new byte[10];
        Arrays.fill(buffer, (byte) ' '); // Fill buffer with spaces as padding
        System.arraycopy(name.getBytes(), 0, buffer, 0, Math.min(name.length(), buffer.length));

        System.out.println("Hello, " + new String(buffer).trim());
    }
}

### Explanation:
취약유형: Buffer Overflow
